package client.cli.org.apache.syncope.client.cli.commands.user;

public class UserDelete extends AbstractUserCommand { private static final Logger LOG = LoggerFactory . getLogger ( UserDelete . class ) ; private static final String DELETE_HELP_MESSAGE = "user --delete {USER-KEY} {USER-KEY} [...]" ; private final Input input ; public UserDelete ( final Input input ) { this . input = input ; } public void delete ( ) { if ( input . parameterNumber ( ) >= 1 ) { for ( final String parameter : input . getParameters ( ) ) { try { userSyncopeOperations . delete ( parameter ) ; userResultManager . deletedMessage ( "User" , parameter ) ; } catch ( final WebServiceException | SyncopeClientException ex ) { LOG . error ( "Error deleting user" , ex ) ; if ( ex . getMessage ( ) . startsWith ( "NotFound" ) ) { userResultManager . notFoundError ( "User" , parameter ) ; } else { userResultManager . genericError ( ex . getMessage ( ) ) ; } } catch ( final NumberFormatException ex ) { LOG . error ( "Error deleting user" , ex ) ; userResultManager . numberFormatException ( "user" , parameter ) ; } } } else { userResultManager . commandOptionError ( DELETE_HELP_MESSAGE ) ; } } }